		sel := gossip.NewRandomPeerSelector(ns.rng.Int63())
		peers := sel.SelectPeers(peerList, nodeID, 1)
		if len(peers) == 0 {
			continue
		}
		peerID := peers[0]
		if ns.isPartitioned(nodeID, peerID) {
			continue
