// recordEvent keeps the newest simulation events while bounding retained memory.
// ns.mu must be held by the caller.
func (ns *NetworkSim) recordEvent(event Event) {
	if len(ns.events) < maxEventLog {
		ns.events = append(ns.events, event)
		return
	}
	copy(ns.events, ns.events[1:])
	ns.events[len(ns.events)-1] = event
}

